class Solution:
    def containsNearbyDuplicate(self, nums: List[int], k: int) -> bool:

        check = defaultdict(int)

        for i, val in enumerate(nums):
            check[val] += 1
            if i-k >= 0:
                check[i-k] -= 1

            if check[val] >= 2:
                return True

        return False

class Solution:
    def containsNearbyDuplicate(self, nums: List[int], k: int) -> bool:

        check = defaultdict(int)

        for i, val in enumerate(nums):
            check[val] += 1

            if check[val] >= 2:
                return True

            if i-k >= 0:
                check[nums[i-k]] -= 1

        return False
